# --- 2. NETWORK & AUTH ---
def get_hydra_w3():
    endpoints = [os.getenv("RPC_URL"), "https://polygon-rpc.com", "https://1rpc.io/matic"]
    for url in endpoints:
        if not url: continue
        try:
            _w3 = Web3(Web3.HTTPProvider(url.strip(), request_kwargs={'timeout': 10}))
            if _w3.is_connected():
                _w3.middleware_onion.inject(ExtraDataToPOAMiddleware, layer=0)
                return _w3
        except: continue
    return None

w3 = get_hydra_w3()
if not w3: exit("FATAL: RPC Failure.")

usdc_e_contract = w3.eth.contract(address=USDC_E, abi=ERC20_ABI)

def get_vault():
    seed = os.getenv("WALLET_SEED", "").strip()
    Account.enable_unaudited_hdwallet_features()
    try:
        return Account.from_mnemonic(seed) if " " in seed else Account.from_key(seed)
    except: return None

vault = get_vault()

def init_clob():
    """Fixes 'Invalid Signature' by enforcing EOA type and refreshing headers."""
    try:
        # Most wallets use 0 (EOA). Change to 1 ONLY if you use a Gnosis Safe/Contract wallet.
        sig_type = int(os.getenv("SIGNATURE_TYPE", 0))
        funder = Web3.to_checksum_address(os.getenv("FUNDER_ADDRESS", vault.address))
        
        client = ClobClient(
            host="https://clob.polymarket.com", 
            key=vault.key.hex(), 
            chain_id=137, 
            signature_type=sig_type, 
            funder=funder
        )
        # Critical: Regenerate creds to sync with the current signature_type
        client.set_api_creds(client.create_or_derive_api_creds())
        return client
    except Exception as e:
        print(f"CLOB Init Error: {e}")
        return None

clob_client = init_clob()

# --- 3. MARKET LOGIC ---
async def get_safe_price(token_id):
    """Deep book scan to prevent FOK reverts."""
    try:
        url = f"https://clob.polymarket.com/book?token_id={token_id}"
        r = await asyncio.to_thread(requests.get, url, timeout=5)
        data = r.json()
        if data.get('asks'):
            depth = min(len(data['asks']) - 1, 2)
            deep_price = float(data['asks'][depth]['price'])
            return min(0.99, round(deep_price + 0.01, 2))
    except: pass
    return 0.99

def calculate_arbitrage_guaranteed(p_yes, p_no, total_capital):
    combined_prob = p_yes + p_no
    if combined_prob <= 0 or combined_prob >= 1.0: return None
    s_y = np.floor(((p_no / combined_prob) * total_capital) * 100) / 100
    s_n = np.floor(((p_yes / combined_prob) * total_capital) * 100) / 100
    roi = round(((1 / combined_prob) - 1) * 100, 2)
    return {"s_y": s_y, "s_n": s_n, "roi": roi}

# --- 4. TELEGRAM INTERFACE ---
async def start(update, context):
    btns = [['🚀 START ARBI-SCAN', '📊 CALIBRATE'], ['💳 VAULT', '🔧 FIX APPROVAL']]
    await update.message.reply_text(f"{LOGO}\n<b>SIGNATURE SECURED. READY.</b>", reply_markup=ReplyKeyboardMarkup(btns, resize_keyboard=True), parse_mode='HTML')

# (scour_arbitrage and main_handler logic omitted for brevity, same as previous versions)

async def handle_query(update, context):
    q = update.callback_query; await q.answer()
    stake = float(context.user_data.get('stake', 10))
    
    if "EXE_" in q.data:
        target = ARBI_CACHE[int(q.data.split("_")[1])]
        calc = calculate_arbitrage_guaranteed(target['p_y'], target['p_n'], stake)
        results = []
        
        for (t_id, amt) in [(target['yes_id'], calc['s_y']), (target['no_id'], calc['s_n'])]:
            try:
                price_limit = await get_safe_price(t_id)
                
                # RE-INITIALIZE payload with correct float rounding for EIP-712
                order_args = MarketOrderArgs(
                    token_id=str(t_id), 
                    amount=float(round(amt, 2)), 
                    side=BUY, 
                    price=float(price_limit)
                )
                
                # Attribute Patch
                if not hasattr(order_args, 'size'):
                    setattr(order_args, 'size', float(round(amt, 2)))

                # SIGNING PROCESS
                # The SDK signs the message using your key and current timestamp
                signed = clob_client.create_market_order(order_args)
                resp = clob_client.post_order(signed, OrderType.FOK)
                
                if resp.get("success") or "order_id" in resp:
                    results.append(True)
                else:
                    print(f"API Refusal: {resp}")
                    results.append(False)
                    
            except Exception as e:
                await context.bot.send_message(q.message.chat_id, f"❌ <b>SDK/Signature Failure:</b> {str(e)}")
                results.append(False)
        
        status = "✅ <b>PROFIT LOCKED</b>" if all(results) else "⚠️ <b>INVALID SIG / FAILED</b>"
        await context.bot.send_message(q.message.chat_id, status, parse_mode='HTML')

